callGraph.callee:
value
		.map((item) => {
			const record = asRecord(item);
			if (!record) return null;
			const name = asString(record.name);
			if (!name) return null;
			return {
				name,
				isError: record.isError === true,
				args:
					typeof record.args === "object" && record.args !== null
						? (record.args as Record<string, unknown>)
						: null,
				result:
					typeof record.result === "string"
						? record.result
						: record.result !== null && record.result !== undefined
							? String(record.result)
							: null,
			};
		})
		.filter

onRestart({
			messageId: message.id,
			prefixMessages,
			payload: resendPayload,
		}).catch

(() => {
					const currentFileMessageCount = countFileMessages(historicalMessages);
					return (
						fileMessageCountAtSendRef.current !== null &&
						currentFileMessageCount > fileMessageCountAtSendRef.current
					);
				})
